import{_ as i,o as t,c as a,a0 as n}from"./chunks/framework.BjpW4enL.js";const u=JSON.parse('{"title":"ADR 0018: Hallucination Detection & MCP Refinement (Gemini Code Review Audit)","description":"","frontmatter":{},"headers":[],"relativePath":"Z_Archive/wiki_legacy/archive/legacy_pre_federation/adr/0018-hallucination-detection-and-mcp-refinement.md","filePath":"Z_Archive/wiki_legacy/archive/legacy_pre_federation/adr/0018-hallucination-detection-and-mcp-refinement.md","lastUpdated":1783623176000}'),s={name:"Z_Archive/wiki_legacy/archive/legacy_pre_federation/adr/0018-hallucination-detection-and-mcp-refinement.md"};function o(r,e,l,c,d,h){return t(),a("div",null,[...e[0]||(e[0]=[n(`<h1 id="adr-0018-hallucination-detection-mcp-refinement-gemini-code-review-audit" tabindex="-1">ADR 0018: Hallucination Detection &amp; MCP Refinement (Gemini Code Review Audit) <a class="header-anchor" href="#adr-0018-hallucination-detection-mcp-refinement-gemini-code-review-audit" aria-label="Permalink to &quot;ADR 0018: Hallucination Detection &amp; MCP Refinement (Gemini Code Review Audit)&quot;">​</a></h1><ul><li><strong>Status:</strong> accepted</li><li><strong>Date:</strong> 2026-06-02</li><li><strong>Author:</strong> Sisyphus &amp; Bruno</li></ul><h2 id="context" tabindex="-1">Context <a class="header-anchor" href="#context" aria-label="Permalink to &quot;Context&quot;">​</a></h2><p>We designed and implemented a <strong>Hallucination Detection</strong> mechanism in Rust to compare deterministic L1 AST constructs against LLM-generated L2 semantic summaries. We also modularized the coordinator&#39;s monolithic <code>main.rs</code> and expanded the MCP server capabilities.</p><p>To validate this feature, we leveraged the <strong>Gemini Code Review</strong> pipeline on Pull Request #15. Given that Gemini Code Assist on GitHub is entering a deprecation phase (sunset by July 2026), we conducted a rigorous, multi-turn review loop to extract maximum value from its static analysis before the service ceases.</p><p>This ADR documents the architectural flaws identified by the AI reviewer, the corresponding engineering fixes, and the design decisions that shaped the final merged state of the <code>draft</code> branch.</p><h2 id="decision-log-review-analysis" tabindex="-1">Decision Log &amp; Review Analysis <a class="header-anchor" href="#decision-log-review-analysis" aria-label="Permalink to &quot;Decision Log &amp; Review Analysis&quot;">​</a></h2><h3 id="_1-database-transaction-isolation-autocommit-stigmergy-migration" tabindex="-1">1. Database Transaction Isolation &amp; Autocommit (Stigmergy Migration) <a class="header-anchor" href="#_1-database-transaction-isolation-autocommit-stigmergy-migration" aria-label="Permalink to &quot;1. Database Transaction Isolation &amp; Autocommit (Stigmergy Migration)&quot;">​</a></h3><ul><li><strong>Review Finding:</strong> Autocommit mode in psycopg2 prevents safe usage of <code>conn.rollback()</code> inside migrations, which would cause runtime crashes on database conflicts.</li><li><strong>Root Cause:</strong> <code>get_db_connection()</code> initializes connections in <code>autocommit = True</code> mode. When a DDL migration block (like <code>CREATE EXTENSION</code>) fails, invoking <code>rollback()</code> on an autocommit connection throws a <code>ProgrammingError</code> since no transaction block is open.</li><li><strong>Engineering Fix:</strong> We temporarily modified <code>nexus_mcp_stigmergy.py</code>&#39;s <code>run_migration()</code> function to explicitly disable autocommit (<code>conn.autocommit = False</code>), utilize SQL <code>SAVEPOINT</code> blocks to isolate pgvector and hallucination column creation, and safely restore the pool connection&#39;s autocommit state in a <code>finally</code> block.</li></ul><h3 id="_2-silent-skip-of-l2-merge-phase" tabindex="-1">2. Silent Skip of L2 Merge Phase <a class="header-anchor" href="#_2-silent-skip-of-l2-merge-phase" aria-label="Permalink to &quot;2. Silent Skip of L2 Merge Phase&quot;">​</a></h3><ul><li><strong>Review Finding:</strong> If L1 (AST) abstractions are vectorized and stored in a prior coordinator pass, subsequent enrichment passes silently skip the L2 (Semantic) merge phase.</li><li><strong>Root Cause:</strong> The <code>vec_rows</code> select query in <code>enrich.rs</code> filtered L1 and L2 rows <code>WHERE vector_id IS NULL</code>. When L1 got its vector_id first, it was excluded from <code>vec_rows</code>. The merge phase built its L1 lookup hashmap solely from <code>vec_rows</code>, meaning L2s would find no matching L1 and skip the merge completely.</li><li><strong>Engineering Fix:</strong> We isolated the query to fetch L2s needing vectorization, and created a separate, targeted query to fetch <em>all</em> L1 content for the referenced <code>blob_ids</code> regardless of whether they have a <code>vector_id</code> or not. We then merged the remaining L1s that actually needed vectorization back into the pipeline loop.</li></ul><h3 id="_3-mutably-indexing-json-values-panic-safety" tabindex="-1">3. Mutably Indexing JSON Values (Panic Safety) <a class="header-anchor" href="#_3-mutably-indexing-json-values-panic-safety" aria-label="Permalink to &quot;3. Mutably Indexing JSON Values (Panic Safety)&quot;">​</a></h3><ul><li><strong>Review Finding:</strong> Mutably indexing serde JSON arrays/objects directly using <code>merged[&quot;purpose&quot;]</code> causes the Rust coordinator to panic if the value is not an Object.</li><li><strong>Root Cause:</strong> Direct bracket indexing (<code>merged[&quot;purpose&quot;] = ...</code>) in <code>serde_json</code> expects the value to match the underlying type and panics if the L1/L2 output is malformed or returned as a non-object from the LLM.</li><li><strong>Engineering Fix:</strong> We refactored <code>enrich.rs</code> to safely check type structures using <code>.as_object_mut()</code> and <code>.insert()</code>:<div class="language-rust vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">rust</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">if</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> let</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> Some</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(merged_obj) </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> merged</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">as_object_mut</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">() {</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    merged_obj</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">insert</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;purpose&quot;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">to_string</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(), purpose</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">clone</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">());</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div></li></ul><h3 id="_4-semantic-hallucination-false-positives" tabindex="-1">4. Semantic Hallucination False Positives <a class="header-anchor" href="#_4-semantic-hallucination-false-positives" aria-label="Permalink to &quot;4. Semantic Hallucination False Positives&quot;">​</a></h3><ul><li><strong>Review Finding:</strong> Character-level <code>contains</code> checks in the hallucination detection module produced false positives by matching substrings (e.g. &quot;User&quot; would erroneously match &quot;UserRepository&quot; or &quot;UserConfig&quot;).</li><li><strong>Root Cause:</strong> <code>l2_text.contains(name)</code> lacks token boundary constraints.</li><li><strong>Engineering Fix:</strong> Refactored <code>hallucination.rs</code> to construct dynamic regex patterns using <strong>word boundaries</strong>:<div class="language-rust vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">rust</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">let</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> pattern </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> format!</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">r&quot;(?i)\\b{}\\b&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">regex</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">::</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">escape</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(name));</span></span></code></pre></div>This guarantees that only exact, separate semantic references are counted as valid mentions, significantly increasing drift metrics accuracy.</li></ul><h3 id="_5-i-o-and-network-optimization-bottlenecks" tabindex="-1">5. I/O and Network Optimization Bottlenecks <a class="header-anchor" href="#_5-i-o-and-network-optimization-bottlenecks" aria-label="Permalink to &quot;5. I/O and Network Optimization Bottlenecks&quot;">​</a></h3><ul><li><strong>Review Findings:</strong> Inefficient I/O reads in <code>ingest.rs</code> and redundant sequential network calls in <code>enrich.rs</code>.</li><li><strong>Root Cause:</strong><ul><li><code>ingest.rs</code> read the entire contents of a file to check for YAML frontmatter metadata.</li><li><code>enrich.rs</code> made sequential <code>get_qdrant_vector</code> requests inside a CPU loop during neighbor-ecosystem fractal filtering.</li></ul></li><li><strong>Engineering Fixes:</strong><ul><li>Modified <code>ingest.rs</code> to open files via <code>File::open</code> and read only the first 1024 bytes using a buffer.</li><li>Converted the sequential neighbor query loops in <code>enrich.rs</code> into concurrent execution blocks using <code>futures::future::join_all</code>.</li></ul></li></ul><h2 id="consequences" tabindex="-1">Consequences <a class="header-anchor" href="#consequences" aria-label="Permalink to &quot;Consequences&quot;">​</a></h2><ul><li><strong>Stability:</strong> Rust Coordinator is resilient against malformed LLM JSON formats and handles I/O gracefully without panic paths.</li><li><strong>Correctness:</strong> Hallucination metrics (T-RAG drift warnings) are mathematically sound and free from substring false positives.</li><li><strong>Rich Context MCP:</strong> Primitives in <code>nexus_adjacent</code> and <code>nexus_reflections</code> now return <code>fs_path</code> alongside database UUIDs, establishing a grounding compass for future AI agents to identify Rust/Angular stacks instantly.</li><li><strong>Weaving Readiness:</strong> The stigmergy script now safely handles transactions via <code>SAVEPOINT</code>s, establishing a stable path for the upcoming <code>weaver.rs</code> implementation.</li></ul>`,19)])])}const p=i(s,[["render",o]]);export{u as __pageData,p as default};
